// Rust verifier scans every X op Y = Z and checks Final Answer.
let mut base = Context::new(&model)?;
base.system(SYSTEM).user(&question).cue();

for attempt in 1..=MAX_RETRIES {
    let mut ctx = base.fork()?;           // KV checkpoint
    let text = ctx.generate(sampler)
        .max_tokens(400)
        .collect_text().await?;

    if verify_attempt(&text, expected).is_empty() {
        return Ok(text);                  // ✓ verifier passed
    }

    // ✗ wrong answer: drop `ctx`, fork base again at higher T.
    sampler = hotter_sampler(attempt);
}
